function UIBaseCtrl:SetMonitorNetIds(ids)
    for k, v in ipairs(ids) do
        self._ui_monitorIds[v] = true
    end
end

function UIBaseCtrl:OnNetRecv(netId, isOk)
    if not self._ui_monitorIds or not self._ui_monitorIds[netId] then
        return
    end
    self._ui_recvNetIds[netId] = nil
end

function UIBaseCtrl:IsNetIdOpOk(netId, ignoreTips)
    local time = self._ui_recvNetIds[netId]
    if not time or time < Time.realtimeSinceStartup then return true end
    if ignoreTips then
        return false
    end
    ShowSysMsg(I18nText(211))
    return false
end

function UIBaseCtrl:RecordNetIdTime(netId)
    self._ui_recvNetIds[netId] = Time.realtimeSinceStartup + 5
end

