---cache list for manager together, map key = self:FindInstanceID(obj)
---@return LxUiLoopList | LxUiFixedList
function UIBaseCtrl:GetUiList(go)
    if not self._uiList_maps then return end
    local instanceId = self:FindInstanceID(go)
    return self._uiList_maps[instanceId]
end

---cache list for manager together, map key = self:FindInstanceID(obj)
---@return LxUiLoopList | LxUiFixedList
function UIBaseCtrl:CreateUiList(go, listType)
    local instanceId = self:FindInstanceID(go)
    local maps = self._uiList_maps
    if not maps then
        maps = {}
        self._uiList_maps = maps
    end
    local list = maps[instanceId]
    if not list then
        if listType == UIListType.Loop then
            list = require("app.component.ui.LxUiLoopList"):new()
        elseif listType == UIListType.Fixed then
            list = require("app.component.ui.LxUiFixedList"):new()
        else
            return
        end
        maps[instanceId] = list
        list:Initialize(go, self)
        list:InitListView()

        if self._isFrozenUIScroll then
            list:Freeze(true)
        end

        return list
    end
end

