---region tween
function UIBaseCtrl:ClearTweenSeq()
    for key, tween in pairs(self._ui_tweenSeqs) do
        if tween and tween.active then
            tween:Kill(false)
        end
    end
    self._ui_tweenSeqs = {}
end

---@param go GameObject
---@param endAction function
---@return DG.Tweening.Sequence
function UIBaseCtrl:NewTweenSeq(go, endAction)
    if IsNull(go) then
        return nil
    end
    local obj = go
    local key = self:FindInstanceID(obj)
    return self:NewTweenSeqByKey(key, endAction, obj)
end

function UIBaseCtrl:NewTweenSeqByKey(key, endAction, obj)
    local oldData = self._ui_tweenSeqs[key]
    if oldData then
        self:RemoveTweenSeqByKey(key)
    end
    local tween = DOTween.Sequence()
    self._ui_tweenSeqs[key] = tween
    tween:OnComplete(function()
        self:RemoveTweenSeqByKey(key)
        if endAction ~= nil then
            endAction(obj)
        end
    end)
    return tween
end

function UIBaseCtrl:RemoveTweenSeqByKey(key)
    if self:IsDisposed() or not self._ui_tweenSeqs then
        return
    end
    local tween = self._ui_tweenSeqs[key]
    if not tween then return end
    if tween and tween.active then
        tween:Kill(false)
    end
    self._ui_tweenSeqs[key] = nil
end

function UIBaseCtrl:RemoveTweenSeq(tarObj)
    if IsNull(tarObj) then
        return
    end
    self:RemoveTweenSeqByKey(self:FindInstanceID(tarObj))
end

function UIBaseCtrl:IsExistTweenSeq(go)
    if IsNull(go) then return nil end
    local key = self:FindInstanceID(go)
    if self._ui_tweenSeqs and self._ui_tweenSeqs[key] then
        return true
    end
    return false
end

function UIBaseCtrl:GetTweenSeq(go)
    if IsNull(go) then return nil end
    local key = self:FindInstanceID(go)
    return self._ui_tweenSeqs[key]
end

