---@param item Transform
---@param iconType number
---@return LxUiIcon, V_IconData @return icon and it's data struct which need fill
function UIBaseCtrl:GetIcon(item, iconType)
    local id = self:FindInstanceID(item)
    local icon = self._ui_icons[id]
    if icon and icon:GetIconType() ~= iconType then
        MgrCenter.ComponentMgr:RecycleIcon(icon)
        self._ui_icons[id] = nil
        icon = nil
    end
    if not icon then
        icon = MgrCenter.ComponentMgr:GetIcon(iconType)
        self._ui_icons[id] = icon
        icon:ChangeParent(item)
    end
    icon:SetOwner(self)
    local iconData = icon:GetData()
    if not iconData then
        iconData = {}
        icon:SetData(iconData)
    end
    return icon, iconData
end

function UIBaseCtrl:RecycleIcons()
    for k, v in pairs(self._ui_icons) do
        MgrCenter.ComponentMgr:RecycleIcon(v)
    end
end

