---@region ui effectDp
---@return LxEffectDp
function UIBaseCtrl:CreateEffDp(key, effName, trans, effLoadCb, effectLoadErrorCb)
    if not key then key = effName end
    if not effName then effName = key end
    ---@type LxEffectDp
    local effDp = self._ui_effectDps[key]
    if effDp and IsValid(effDp:GetDpGo()) then
        ShowObject(effDp:GetDpGo(), true)
        if effLoadCb then
            effLoadCb(effDp)
        end
        return effDp
    end

    effDp = require("app.component.dp.LxEffectDp"):new()
    self._ui_effectDps[key] = effDp

    effDp:InitUIDp(effName, trans)
    effDp:SetLoadedCallback(effLoadCb)
    effDp:SetLoadFailCallback(effectLoadErrorCb)
    effDp:SetRendererLayer(self:GetUiLayerName(), self:GetUiOrder())
    effDp:SetUICanvasLayer(self:GetUiLayerName(), self:GetUiOrder())
    effDp:SetScale(1)
    effDp:SetLocalPosition(Vector3.one)
    effDp:Load()
    return effDp
end

---@param effectParams V_UI_CreateEffDpIml_PARAM
function UIBaseCtrl:CreateEffDpIml(effectParams)
    local key = effectParams.key
    local effLoadCb = effectParams.effLoadCb
    local effLoadErr = effectParams.effLoadErr
    local effectDp = self:GetEffDp(key)
    if effectDp then
        if effectDp:IsDpValid() then
            local dpGo = effectDp:GetDpGo()
            ShowObject(dpGo, false)
            ShowObject(dpGo, true)
            if effLoadCb then
                effLoadCb(effectDp)
            end
        else
            if effLoadErr then
                effLoadErr(effectDp)
            end
        end
        return
    end

    local order = effectParams.order or 0

    effectDp = require("app.component.dp.LxEffectDp"):new()
    self._ui_effectDps[key] = effectDp
    effectDp:InitUIDp(effectParams.effName, effectParams.trans)
    effectDp:SetRendererLayer(self:GetUiLayerName(), self:GetUiOrder() + order)
    effectDp:SetUICanvasLayer(self:GetUiLayerName(), self:GetUiOrder() + order)
    local scale = effectParams.scale or 1
    effectDp:SetScale(scale)
    if effectParams.localPos then
        effectDp:SetLocalPosition(effectParams.localPos)
    end
    if effectParams.layer then
        effectDp:SetMaskLayer(effectParams.layer)
    end
    effectDp:SetAddMask(effectParams.addMask)
    effectDp:SetLoadedCallback(effLoadCb)
    effectDp:SetLoadFailCallback(effLoadErr)
    effectDp:Load()
end

function UIBaseCtrl:RemoveEffDp(key)
    local effDp = self._ui_effectDps[key]
    if effDp then
        effDp:Dispose()
    end
    self._ui_effectDps[key] = nil
end

function UIBaseCtrl:ClearEffDp()
    for k, v in pairs(self._ui_effectDps) do
        v:Dispose()
    end
    self._ui_effectDps = {}
end

---@return LxEffectDp
function UIBaseCtrl:GetEffDp(key)
    return self._ui_effectDps[key]
end

