---@region ui LxSpineDp
function UIBaseCtrl:CreateSpineDpIml(spineParams)
    local spineName = spineParams.spineName
    if not spineName or spineName == "" then
        if LOG_INFO_ENABLED then
            printError("UIBaseCtrl:", "spineParams not set spineName")
        end
        return
    end

    local trans = spineParams.trans
    if not IsValid(trans) then
        if LOG_INFO_ENABLED then
            printError("UIBaseCtrl:", "spineParams not set trans")
        end
        return
    end

    local key = spineParams.key
    if not key then
        key = self:FindInstanceID(trans)
    end


    local loadCb = spineParams.loadCb

    ---@type LxSpineDp
    local spineDp = self:GetSpineDp(key)
    if spineDp then
        local dpTrans = spineDp:GetDpTrans()
        if spineParams.reset then
            if spineDp:GetModelName() == spineName then
                return spineDp
            else
                dpTrans = nil
            end
        end

        if IsValid(dpTrans) then
            if loadCb then
                loadCb(spineDp)
            end
            return
        end
        spineDp:Dispose()
    end

    spineDp = require("app.component.dp.LxSpineDp"):new()

    self._ui_spineDps[key] = spineDp

    spineDp:InitUIDp(spineName, trans)
    ---@param dpSpine LxSpineDp
    spineDp:SetLoadedCallback(function(dpSpine)
        ---@type Transform
        local dpTrans = dpSpine:GetDpTrans()
        if spineParams.isdCenter then
            dpTrans.anchorMin = Vector2(0.5, 0.5)
            dpTrans.anchorMax = Vector2(0.5, 0.5)
            dpTrans.pivot = Vector2(0.5, 0.5)
        end
        dpTrans.anchoredPosition = Vector3.zero

        local scale = 1
        local scaleNum = spineParams.scaleNum
        if scaleNum and scaleNum > 0 then
            scale = scaleNum
        end
        dpSpine:SetScale(scale)

        if spineParams.isFlipX then
            dpSpine:SetFlipX(true)
        end

        if loadCb then
            loadCb(dpSpine)
        end
    end)
    if not spineParams.bNotLoaded then
        spineDp:Load()
    end
    return spineDp
end

function UIBaseCtrl:ClearSpineDp()
    for k, v in pairs(self._ui_spineDps) do
        v:Dispose()
    end
    self._ui_spineDps = {}
end

function UIBaseCtrl:RemoveSpineDp(key)
    if not self._ui_spineDps[key] then return end
    local spineDp = self._ui_spineDps[key]
    spineDp:Dispose()
    self._ui_spineDps[key] = nil
end

---@return LxSpineDp
function UIBaseCtrl:GetSpineDp(key)
    return self._ui_spineDps[key]
end

---@endregion ui LxSpineDp
