--- 按钮预制 btn_cost
---@param btn CButton
---@param priceType number
---@param expend number|string 计费点id 或者 道具消耗字符串
---@param textId number
function UIBaseCtrl:SetAutoRootCommonBtnName(btn,priceType,expend,textId)
    local btnTrans = btn.transform
    local IconRoot = LxUiHelper.FindChild(btnTrans,"IconRoot")

    local showIconRoot = false
    local btnStr = ""
    if priceType == ShopPriceType.RMB then
        btnStr = CtrlCenter.Pay:GetWelfarePayNumShowStr(checknumber(expend))
    elseif priceType == ShopPriceType.CURRENCY then
        ---@type V_Item
        local expendInfo = LxDataHelper.ParseItem(expend)
        if expendInfo then
            local Icon = LxUiHelper.FindImage(IconRoot,"Icon")
            self:SetImage(Icon,LxDataHelper.GetItemIcon(expendInfo.refId))
            btnStr = LxDataHelper.FormatFullPriceNum(expendInfo.num)
            showIconRoot = true
        end
    elseif priceType == ShopPriceType.FREE then
        btnStr = I18nText(11110)
    end
    ShowObject(IconRoot.gameObject,showIconRoot)

    if textId and textId > 0 then
        btnStr = I18nText(textId, btnStr)
    end

    local BtnName = LxUiHelper.FindText(btnTrans, "BtnName")
    if not IsNull(BtnName) then
        self:SetText(BtnName,btnStr)
    end
    BtnName = LxUiHelper.FindText(btnTrans, "BtnNameGray")
    if not IsNull(BtnName) then
        self:SetText(BtnName,btnStr)
    end
end

