--- 仅显示，隐藏 状态的按钮，属于通用按钮来的
function UIBaseCtrl:SetFuncOpenCommonBtn(funcBtnInfo)
    if not funcBtnInfo then return end

    ---@type CButton
    local btn = funcBtnInfo.btn
    ---@type number
    local funcId = funcBtnInfo.funcId
    local setBtnName = true
    if funcBtnInfo.noSetName then
        setBtnName = false
    end
    if setBtnName then
        self:SetCommonBtnName(btn, self:GetFuncOpenBtnName(funcId, funcBtnInfo.btnName))
    end
    self:SetCommonFuncOpenBtn(funcBtnInfo)
    self:RefreshFuncOpenCommonBtn(btn, funcId)
end

---@param btn CButton
function UIBaseCtrl:RefreshFuncOpenCommonBtn(btn, funcId)
    ---@type Transform
    local btnObj = btn.gameObject
    local showBtn = true
    if funcId and funcId > 0 then
        if not CtrlCenter.FuncOpen:IsFuncShow(funcId) then
            showBtn = false
        end
    end
    ShowObject(btnObj, showBtn)
end

function UIBaseCtrl:SetCommonFuncOpenBtn(funcBtnInfo)
    if not funcBtnInfo then return end

    ---@type number
    local funcId = funcBtnInfo.funcId
    ---@type function
    local btnFunc = funcBtnInfo.btnFunc
    local hasFuncId = funcId and funcId > 0
    if not btnFunc and hasFuncId then
        btnFunc = function()
            CtrlCenter.FuncOpen:JumpTo(funcId, funcBtnInfo.skipValidOpen, funcBtnInfo.jumpParams)
        end
    end
    self:SetUIClick(funcBtnInfo.btn, function()
        if hasFuncId then
            if not CtrlCenter.FuncOpen:IsFuncOpen(funcId, true) then
                return
            end
        end
        if btnFunc then
            btnFunc()
        end
    end)
end

