-- 简单列表
function UIBaseCtrl:SetComList(rootTrans, dataList, drawItemCall)
    local instanceID = self:FindInstanceID(rootTrans)
    local itemCache = self:GetComponentCache(instanceID)
    if not itemCache then
        itemCache = {}
        local trans = LxUiHelper.FindChild(rootTrans, "Item")
        if not trans then
            trans = LxUiHelper.FindChild(rootTrans, "Content/Item")
        end
        if not trans then
            printError("Item 节点找不到" .. rootTrans.name)
            return
        end

        itemCache.parent = trans.parent
        itemCache.obj = trans.gameObject
        itemCache.uiList = {}
        ShowObject(itemCache.obj, false)
        self:SetComponentCache(instanceID, itemCache)
    end

    if not itemCache.uiList then
        return
    end

    for k, data in ipairs(dataList) do
        local uiList = itemCache.uiList[k]
        if not uiList then
            local obj = InstantObject(itemCache.obj)
            local trans = obj.transform
            trans:SetParent(itemCache.parent, false)
            uiList = drawItemCall(nil, trans, data, k)
            uiList.trans = trans
            uiList.obj = obj
            itemCache.uiList[k] = uiList
        else
            drawItemCall(uiList, uiList.trans, data, k)
        end
        uiList.trans.name = k
        ShowObject(uiList.obj, true)
    end
    for i = #dataList + 1, #itemCache.uiList do
        ShowObject(itemCache.uiList[i].obj, false)
    end
end

-- 设置红点(第一层的子节点需要带ObjRed)
function UIBaseCtrl:SetRed(trans, isShow)
    if IsNull(trans) then
        return
    end

    local instanceID = self:FindInstanceID(trans) + 0.1 -- 加小数点一位保证唯一性，trans可能在其它地方也以同样方式设置Cache
    local itemCache = self:GetComponentCache(instanceID)
    local objRed
    if not itemCache then
        objRed = LxUiHelper.FindChildObj(trans, "ObjRed")
        itemCache = { _base_ObjRed = objRed }
        self:SetComponentCache(instanceID, itemCache)
    else
        objRed = itemCache._base_ObjRed
    end
    if not objRed then
        printError("UIBaseCtrl", "ObjRed 节点找不到" .. tostring(trans.name))
        return
    end
    ShowObject(objRed, isShow)
end

