end

--[[
    item = CostItem1 节点（自带 Horizontal Layout Group 组件）
    data = {
        refId:道具的refId(必传),
        needNum:消耗所需数量(必传),
        num:作用与needNum相同,为了兼容 LxDataHelper.ParseItem(str),

        isHideRoot:是否显示整个节点(默认false),
        isHideIcon:是否显示Icon(默认false),
        simpleShow:简单展示，没有颜色区别(默认false)
        enoughColor:满足的颜色
        notEnoughColor:不满足的颜色
        isHideNeedNum:是否隐藏消耗数量(默认false)
        matName: 描边材质球名字
    }
]]
function UIBaseCtrl:SetCostItem(item, data)
    local instanceID = self:FindInstanceID(item)
    local itemCache = self:GetComponentCache(instanceID)
    if not itemCache then
        ---@type Transform
        local IconRoot = LxUiHelper.FindChild(item, "IconRoot")
        local Icon = LxUiHelper.FindImage(IconRoot, "Icon")
        itemCache = {
            Root = item.gameObject,
            IconRootObj = IconRoot.gameObject,
            Icon = Icon,
            IconObj = Icon.gameObject,
            CostNum = LxUiHelper.FindText(item, "CostNum"),
        }
        self:SetComponentCache(instanceID, itemCache)
    end
    local isHideRoot = data.isHideRoot
    if isHideRoot then
        ShowObject(itemCache.Root, false)
        return
    end
    local refId = data.refId
    local bHideIcon = data.isHideIcon
    local bShowIcon = not bHideIcon
    if bShowIcon then
        self:SetImage(itemCache.Icon, LxDataHelper.GetItemIcon(refId))
    else
        self:EnableImage(itemCache.Icon, false)
    end
    local hasNum = ModuleCenter.Item:GetItemCount(refId)
    local needNum = data.needNum or data.num
    local showStr = ""
    if data.simpleShow then
        showStr = string.replace("#a1#/#a2#", LxDataHelper.FormatNum(hasNum), needNum)
    else
        local isEnough = hasNum >= needNum
        local color
        if isEnough then
            color = data.enoughColor or "#187b07"
        else
            color = data.notEnoughColor or "#b50808"
        end
        if data.isHideNeedNum then
            showStr = string.replace("<color=#a1#>#a2#</color>", color, needNum)
        else
            showStr = string.replace("<color=#a1#>#a2#</color>/#a3#", color, LxDataHelper.FormatNum(hasNum), needNum)
        end
    end
    if data.matName then
        self:SetTextMat(itemCache.CostNum, data.matName)
    end
    self:SetText(itemCache.CostNum, showStr)
    ShowObject(itemCache.Root, true)
end

-- 设置空列表提示
function UIBaseCtrl:ShowEmptyTips(obj, refId, bShow, jumpFunc)
    ShowObject(obj, bShow)
    if not bShow then
        return
    end

    local trans = obj.transform
    local instanceID = self:FindInstanceID(trans)
    local itemCache = self:GetComponentCache(instanceID)
    if not itemCache then
        itemCache = {
            obj1  = LxUiHelper.FindChildObj(trans, "ObjType1"),
            obj2  = LxUiHelper.FindChildObj(trans, "ObjType2"),
            txt1  = LxUiHelper.FindText(trans, "ObjType1/bg/TxtDesc1"),
            txt2  = LxUiHelper.FindText(trans, "ObjType2/TxtDesc2"),
            btn   = LxUiHelper.FindButton(trans, "BtnJump"),
            refId = 0
        }
        itemCache.objBtn = itemCache.btn.gameObject
        self:SetComponentCache(instanceID, itemCache)
    end

    if itemCache.refId == refId then
        return
    end

    local refData = GameTable.EmptyListRef[refId]
    if not refData then
        if LOG_INFO_ENABLED then
            printInfo("EmptyList", "emptylist not support refId = %s", tostring(refId))
        end
        return
    end

    -- 按钮
    local btn = itemCache.btn
    self:SetCommonBtnName(btn, I18nText(refData.btnName))
    local jumpId = refData.jumpId
    local originItem = refData.originItem
    self:SetUIClick(btn, function()
        if jumpFunc then
            jumpFunc()
            return
        end
        if BuildFuncOpenIds[jumpId] then --打开建筑界面跳转
            self:CloseSelf()
            local buildId = BuildFuncOpenIds[jumpId]
            CtrlCenter.City:MoveToBuildObjPanel(buildId)
            return
        end
        if originItem > 0 then
            ShowPanel(UiNames.ItemOrigin, {refId = originItem, from = self:GetUiName()})
            return
        end
        CtrlCenter.FuncOpen:JumpTo(jumpId)
    end)
    ShowObject(itemCache.objBtn, refData.btn > 0)

    -- 文字
    local desc = I18nText(refData.text)
    self:SetText(itemCache.txt1, desc)
    self:SetText(itemCache.txt2, desc)

    -- 类型
    local isType1 = refData.showImg > 0
    ShowObject(itemCache.obj1, isType1)
    ShowObject(itemCache.obj2, not isType1)
end

-- 刷新 Bottom tab
--[[
    dataList = {{
        icon = "", 图标路径（必传）
        funcId = nil, 功能id（传此值时，名字/红点/锁，都使用此值）
        btnName = "", 按钮文字
        showRed = false, 是否显示红点
        showLock = false, 是否显示锁
    }}
--]]
function UIBaseCtrl:RefreshBottomTab(dataList, selectIndex)
    if not self._bottomTabUiList then
        local trans = self.mBottomTabList
        self._bottomTabSelectIndex = selectIndex or 1
        if not trans then
            printError("InitBottomTab", "self.mBottomTabList is nil")
            return
        end
        self._bottomTabUiList = {}
        self:SetComList(trans, dataList, function(...) return self:OnDrawBottomTabItem(...) end)
        self:SetBtnSelected(self._bottomTabUiList[self._bottomTabSelectIndex].btn, true)
        return
    end

    -- 刷新
    for i, uiList in ipairs(self._bottomTabUiList) do
        local data = uiList.data
        local funcId = data.funcId
        local showRed = false
        local showLock = false
        if funcId then
            showRed = CtrlCenter.RedPoint:GetRedNum(funcId) > 0
            showLock = not CtrlCenter.FuncOpen:IsFuncOpen(funcId, false)
        else
            if data.showRed ~= nil then
                showRed = data.showRed
            end
            if data.showLock ~= nil then
                showLock = data.showLock
            end
        end
        ShowObject(uiList.objRed, showRed)
        ShowObject(uiList.objLock, showLock)

        if selectIndex then
            self:SetBtnSelected(uiList.btn, i == selectIndex)
        end
    end
    if selectIndex then
        self._bottomTabSelectIndex = selectIndex
    end
end

-- Bottom tab列表 item
function UIBaseCtrl:OnDrawBottomTabItem(uiList, trans, data, index)
    if not uiList then
        uiList             = {}
        uiList.btn         = LxUiHelper.FindButton(trans)
        uiList.icon        = LxUiHelper.FindImage(trans, "Icon")
        uiList.objLock     = LxUiHelper.FindChildObj(trans, "ObjLock")
    end
    uiList.data = data
    self._bottomTabUiList[index] = uiList

    local funcId = data.funcId
    local btnName = data.btnName or ""
    local icon = data.icon

    self:SetImage(uiList.icon, icon)

    local showLock = false
    if funcId then
        btnName = ModuleCenter.FuncOpen:GetFuncMgrName(funcId)
        showLock = not CtrlCenter.FuncOpen:IsFuncOpen(funcId, false)
    end
    self:SetTabBtnName(uiList.btn, btnName)
    ShowObject(uiList.objLock, showLock)

    self:SetUIClick(uiList.btn, function()
        if self._bottomTabSelectIndex == index then
            return
        end
        if funcId then
            if not CtrlCenter.FuncOpen:IsFuncOpen(funcId, true) then
                return
            end
        end
        self:SetBtnSelected(self._bottomTabUiList[self._bottomTabSelectIndex].btn, false)
        self:SetBtnSelected(self._bottomTabUiList[index].btn, true)
        self._bottomTabSelectIndex = index
        self:OnClickBottomTab(data, index)
    end)

    return uiList
end

