--- @param item Transform
function UIBaseCtrl:GetUiAttrItem(item)
    local id = self:FindInstanceID(item)
    local attrItem = self._ui_attrItems[id]
    if not attrItem then
        attrItem = require("app.ui.item.LxUiAttributeItem"):new(self, item)
        self._ui_attrItems[id] = attrItem
        attrItem:Initialize()
    end
    return attrItem
end

function UIBaseCtrl:ClearUiAttrItems()
    for k, v in pairs(self._ui_attrItems) do
        v:Dispose()
    end
end

---@param qualityRoot Transform 品质节点
---@param factRoot Transform 具体的宽高
function UIBaseCtrl:SetUIQualityEffect(qualityRoot,quality,factRoot,extra)
    local key = self:FindInstanceID(qualityRoot)
    local effDp = self:GetEffDp(key)
    if effDp then
        self:RemoveEffDp(key)
    end

    ---@type V_QualityRef
    local qualityRef = LxDataHelper.GetQualityRef(quality)
    if not qualityRef or string.isempty(qualityRef.iconTipBg) then return end

    local obj = qualityRoot.gameObject
    ShowObject(obj,false)
    self:CreateEffDpIml({
        key = key,
        effName = qualityRef.iconTipBg,
        trans = qualityRoot,
        localPos = Vector3.zero,
        effLoadCb = function(dp)
            self:DelayUIQualityEffectShow(dp,factRoot,obj,extra)
        end
    })
end

---@param dp LxEffectDp
---@param factRoot Transform 实际宽高节点
---@param root GameObject 特效挂载的节点
function UIBaseCtrl:DelayUIQualityEffectShow(dp,factRoot,root,extra)
    if dp:IsNull() then return end

    extra = extra or {}
    local offsetX = extra.offsetX or 130
    local offsetY = extra.offsetY or 160
    self:StopTimer("__SetQualityEffectTimer")
    self:StartFrameTimer("__SetQualityEffectTimer",1,false,1,function()
        local sizeDelta = factRoot.sizeDelta
        local width = sizeDelta.x + offsetX
        local height = sizeDelta.y + offsetY
        local dpTrans = dp:GetDpTrans()
        dpTrans.localScale = Vector3(width,height,0)

        ShowObject(root,true)
        self:StopTimer("__SetQualityEffectTimer")
    end)
end

