--- 通用奖励道具列表
--- @param obj GameObject
--- @param dataList table 奖励道具列表 {"1=101003=1","1=101003=1"}
function UIBaseCtrl:SetCommonIconList(obj, dataList, uiListType)
    if obj == nil or dataList == nil then
        return
    end
    local uiList = self:GetUiList(obj)
    if not uiList then
        uiListType = uiListType or UIListType.Fixed
        uiList = self:CreateUiList(obj, uiListType)
        uiList:SetDrawItemCb(function(...) self:OnDrawCommonIconList(...) end)
    end
    uiList:AddDatas(dataList)
    uiList:RefreshList()
end
function UIBaseCtrl:OnDrawCommonIconList(list, item, itemData, index)
    local instanceID = self:FindInstanceID(item)
    local itemCache = self:GetComponentCache(instanceID)
    if not itemCache then
        local itemRootTrans = LxUiHelper.FindChild(item, "CommonUi")
        itemCache = {
            itemRoot = itemRootTrans,
        }
        self:SetComponentCache(instanceID, itemCache)
    end
    local itemParse = LxDataHelper.ParseItem(itemData)
    local icon,iconData = self:GetIcon(itemCache.itemRoot, itemParse.type)
    local itemPos
    iconData.refId = itemParse.refId
    iconData.num = itemParse.num
    icon:SetClickFunc(function()
        if itemParse.type == ThingType.People or itemParse.type == ThingType.Soldier then
            itemPos = itemCache.itemRoot.position
        end
        FireEvent(EventNames.SHOW_TIPS,{
            type = itemParse.type,
            viewType = 2,
            refData = itemParse,
            refId = itemParse.refId,
            itemPos = itemPos,
        })
    end)
    icon:Show()
end

function UIBaseCtrl:InitList(onDrawItemCb, list, listObj, listType)
    local uiList = self:GetUiList(listObj)
    if not uiList then
        uiList = self:CreateUiList(listObj, listType or UIListType.Fixed)
        uiList:SetDrawItemCb(onDrawItemCb)
    end
    uiList:AddDatas(list)
    uiList:RefreshList()
    return uiList
end
function UIBaseCtrl:SetBtnIcon(btn, iconRes)
    if not IsValid(btn) then
        return
    end
    local icon = LxUiHelper.FindImage(btn.transform, "Icon")
    self:SetImage(icon, iconRes)
end


function UIBaseCtrl:FreezeUIScroll(bFrozen)
    if self._isFrozenUIScroll == bFrozen then
        return
    end

    if not self:IsChildCtrl() then
        local _childCtrls = self._childCtrls
        for k, v in pairs(_childCtrls) do
            v:FreezeUIScroll(bFrozen)
        end
    end

    self._isFrozenUIScroll = bFrozen

    local uiList_maps = self._uiList_maps
    if (not uiList_maps) then
        return
    end
    for k, v in pairs(uiList_maps) do
        v:Freeze(bFrozen)
    end
end

return UIBaseCtrl
